@php $objectId=$objectId??null; if(!$objectId) return; $classification=\Illuminate\Support\Facades\DB::table("object_security_classification as osc")->join("security_classification as sc","sc.id","=","osc.classification_id")->where("osc.object_id",$objectId)->where("osc.active",1)->select("sc.code","sc.name","sc.level")->first(); if(!$classification) return; $colors=["PUBLIC"=>"success","INTERNAL"=>"info","CONFIDENTIAL"=>"primary","SECRET"=>"warning","TOP_SECRET"=>"danger"]; @endphp
<span class="badge bg-{{ $colors[$classification->code]??"secondary" }} classification-badge-sm ms-1" title="{{ e($classification->name) }}"><i class="fas fa-shield-alt"></i></span>